SELECT COUNT(*) AS QUANTIDADE FROM lattes_p_prodtec AS LP JOIN lattes_prodtec AS PT ON PT.pk = LP.fk_prodtec JOIN servidor AS S ON S.pk_siape = LP.fk_siape WHERE S.genero = 'FEMININO' AND S.sigla_campus = 'ANA' AND (LOWER(S.area_ingresso) LIKE '%letras%' OR LOWER(S.area_ingresso_og) LIKE '%letras%') AND LOWER(PT.natureza) LIKE '%organizacao%' AND PT.ano >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4)